import{_ as s,c as a,a as e,o as t}from"./app-CddT6UHG.js";const o={};function c(p,n){return t(),a("div",null,n[0]||(n[0]=[e(`<h1 id="context" tabindex="-1"><a class="header-anchor" href="#context"><span>Context</span></a></h1><p>In this section, we will explore the fundamental element of FluxaORM: the <code>fluxaorm.Context</code> interface, and discover how to create and effectively use it.</p><p>In the previous chapter, you learned how to create the <code>Engine</code> object, an essential component for accessing data pools and managing registered entities. The <code>Context</code> plays a pivotal role in all FluxaORM operations -- it is typically the first argument to every Provider method, facilitating data retrieval and modification in your databases.</p><h2 id="creating-a-context" tabindex="-1"><a class="header-anchor" href="#creating-a-context"><span>Creating a Context</span></a></h2><p>To create a <code>fluxaorm.Context</code>, call the <code>NewContext()</code> method on an <code>Engine</code> object, passing a standard <code>context.Context</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token string">&quot;context&quot;</span></span>
<span class="line">    <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    registry <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRegistry</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token comment">// ... register data pools and entities</span></span>
<span class="line">    engine<span class="token punctuation">,</span> err <span class="token operator">:=</span> registry<span class="token punctuation">.</span><span class="token function">Validate</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line highlighted">    ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>In a web application, you would typically create a new <code>Context</code> for each incoming request, using the request&#39;s <code>context.Context</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token function">handleRequest</span><span class="token punctuation">(</span>w http<span class="token punctuation">.</span>ResponseWriter<span class="token punctuation">,</span> r <span class="token operator">*</span>http<span class="token punctuation">.</span>Request<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>r<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token comment">// use ctx for all database operations in this request</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="context-interface" tabindex="-1"><a class="header-anchor" href="#context-interface"><span>Context Interface</span></a></h2><p>The <code>fluxaorm.Context</code> interface provides the following methods:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> Context <span class="token keyword">interface</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// Returns the underlying standard context.Context</span></span>
<span class="line">    <span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span> context<span class="token punctuation">.</span>Context</span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Creates a copy of this Context sharing metadata and debug settings</span></span>
<span class="line">    <span class="token function">Clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span> Context</span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Creates a copy with a different context.Context</span></span>
<span class="line">    <span class="token function">CloneWithContext</span><span class="token punctuation">(</span>context context<span class="token punctuation">.</span>Context<span class="token punctuation">)</span> Context</span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Returns the Engine that created this Context</span></span>
<span class="line">    <span class="token function">Engine</span><span class="token punctuation">(</span><span class="token punctuation">)</span> Engine</span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Disables the per-request context cache</span></span>
<span class="line">    <span class="token function">DisableContextCache</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Sets the time-to-live for context cache entries</span></span>
<span class="line">    <span class="token function">SetContextCacheTTL</span><span class="token punctuation">(</span>ttl time<span class="token punctuation">.</span>Duration<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Flushes all tracked entity changes to MySQL and Redis</span></span>
<span class="line">    <span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">error</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Flushes changes asynchronously via Redis Streams</span></span>
<span class="line">    <span class="token function">FlushAsync</span><span class="token punctuation">(</span>immediateRedisUpdates <span class="token builtin">bool</span><span class="token punctuation">)</span> <span class="token builtin">error</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Returns an async SQL consumer for processing queued FlushAsync operations</span></span>
<span class="line">    <span class="token function">GetAsyncSQLConsumer</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>AsyncSQLConsumer<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Discards all tracked entity changes without flushing</span></span>
<span class="line">    <span class="token function">ClearFlush</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Returns a Redis pipeline for batching Redis commands</span></span>
<span class="line">    <span class="token function">RedisPipeLine</span><span class="token punctuation">(</span>pool <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token operator">*</span>RedisPipeLine</span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Returns a database pipeline for batching SQL queries</span></span>
<span class="line">    <span class="token function">DatabasePipeLine</span><span class="token punctuation">(</span>pool <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token operator">*</span>DatabasePipeline</span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Registers a query logger for observing executed queries</span></span>
<span class="line">    <span class="token function">RegisterQueryLogger</span><span class="token punctuation">(</span>handler LogHandler<span class="token punctuation">,</span> mysql<span class="token punctuation">,</span> redis<span class="token punctuation">,</span> local <span class="token builtin">bool</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Enables debug logging for all query types</span></span>
<span class="line">    <span class="token function">EnableQueryDebug</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Enables debug logging for specific query types</span></span>
<span class="line">    <span class="token function">EnableQueryDebugCustom</span><span class="token punctuation">(</span>mysql<span class="token punctuation">,</span> redis<span class="token punctuation">,</span> local <span class="token builtin">bool</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Stores a metadata key-value pair</span></span>
<span class="line">    <span class="token function">SetMetaData</span><span class="token punctuation">(</span>key<span class="token punctuation">,</span> value <span class="token builtin">string</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Returns all stored metadata</span></span>
<span class="line">    <span class="token function">GetMetaData</span><span class="token punctuation">(</span><span class="token punctuation">)</span> Meta</span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Tracks an entity for the next Flush() call</span></span>
<span class="line">    <span class="token function">Track</span><span class="token punctuation">(</span>e Entity<span class="token punctuation">,</span> cacheIndex <span class="token builtin">uint64</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Returns the event broker for publishing/subscribing to entity events</span></span>
<span class="line">    <span class="token function">GetEventBroker</span><span class="token punctuation">(</span><span class="token punctuation">)</span> EventBroker</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="flushing-changes" tabindex="-1"><a class="header-anchor" href="#flushing-changes"><span>Flushing Changes</span></a></h2><p>The <code>Flush()</code> method is one of the most important operations in FluxaORM. When you create, modify, or delete entities, those changes are not sent to the database immediately. Instead, entities are tracked in memory, and all changes are persisted in a single batch when you call <code>Flush()</code>.</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Create and modify entities</span></span>
<span class="line">user <span class="token operator">:=</span> entities<span class="token punctuation">.</span>UserProvider<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">SetName</span><span class="token punctuation">(</span><span class="token string">&quot;Alice&quot;</span><span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">SetEmail</span><span class="token punctuation">(</span><span class="token string">&quot;alice@example.com&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">product <span class="token operator">:=</span> entities<span class="token punctuation">.</span>ProductProvider<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line">product<span class="token punctuation">.</span><span class="token function">SetName</span><span class="token punctuation">(</span><span class="token string">&quot;Widget&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Persist all changes at once</span></span>
<span class="line">err <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Flush()</code> executes the following steps in order:</p><ol><li>Calls <code>PrivateFlush()</code> on each tracked entity, which builds the necessary SQL queries and Redis commands.</li><li>Executes all batched SQL queries via database pipelines.</li><li>Executes all batched Redis commands via Redis pipelines.</li><li>Marks all tracked entities as flushed and clears the tracking list.</li></ol><h3 id="asynchronous-flush" tabindex="-1"><a class="header-anchor" href="#asynchronous-flush"><span>Asynchronous Flush</span></a></h3><p><code>FlushAsync(immediateRedisUpdates)</code> works similarly to <code>Flush()</code>, but instead of executing SQL queries directly against MySQL, it publishes them to a Redis Stream. When <code>immediateRedisUpdates</code> is <code>true</code>, Redis cache and search indexes are updated immediately (optimistic update). When <code>false</code>, all Redis operations are deferred to the consumer alongside the SQL queries. A separate consumer process retrieves and executes the queued operations asynchronously.</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">err <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">FlushAsync</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To process the queued SQL operations, create a consumer:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">consumer<span class="token punctuation">,</span> err <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetAsyncSQLConsumer</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token comment">// Run the consumer in a goroutine or dedicated worker</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="clearing-tracked-changes" tabindex="-1"><a class="header-anchor" href="#clearing-tracked-changes"><span>Clearing Tracked Changes</span></a></h3><p>If you want to discard all pending changes without flushing, use <code>ClearFlush()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">user <span class="token operator">:=</span> entities<span class="token punctuation">.</span>UserProvider<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">SetName</span><span class="token punctuation">(</span><span class="token string">&quot;Alice&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Changed your mind -- discard everything</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">ClearFlush</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="entity-tracking" tabindex="-1"><a class="header-anchor" href="#entity-tracking"><span>Entity Tracking</span></a></h2><p>When you create a new entity via <code>Provider.New()</code> or <code>Provider.NewWithID()</code>, it is automatically tracked by the Context. When you modify an existing entity (via any setter), it is also automatically tracked. You do not need to manually track entities in normal usage.</p><p>The <code>Track()</code> method is used internally by generated code. Each call to a setter that changes a value will call <code>Track()</code> automatically to ensure the entity is included in the next <code>Flush()</code>.</p><h2 id="query-debug" tabindex="-1"><a class="header-anchor" href="#query-debug"><span>Query Debug</span></a></h2><p>You can activate debug mode to observe all queries executed against MySQL, Redis, and the local cache.</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Enable debug logging for all query types</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">EnableQueryDebug</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Enable debug logging for specific types only</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">EnableQueryDebugCustom</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>  <span class="token comment">// MySQL only</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">EnableQueryDebugCustom</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>   <span class="token comment">// MySQL and Redis</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">EnableQueryDebugCustom</span><span class="token punctuation">(</span><span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span>  <span class="token comment">// Local cache only</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Every query is displayed in two lines. The first line contains:</p><ul><li>FluxaORM logo</li><li>Query source (MySQL, Redis, local cache)</li><li>Data pool name</li><li>Operation type</li><li>Query time in milliseconds</li></ul><p>The length of the indicator bar correlates with query time -- longer and more red for slower queries, helping you identify performance issues. The full query is displayed on the second line.</p><h3 id="custom-query-loggers" tabindex="-1"><a class="header-anchor" href="#custom-query-loggers"><span>Custom Query Loggers</span></a></h3><p>For production use, you can register custom query loggers that implement the <code>LogHandler</code> interface:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx<span class="token punctuation">.</span><span class="token function">RegisterQueryLogger</span><span class="token punctuation">(</span>myLogger<span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span> <span class="token comment">// MySQL + Redis</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="metadata" tabindex="-1"><a class="header-anchor" href="#metadata"><span>Metadata</span></a></h2><p>You can use the Context to store request-scoped key-value metadata using <code>SetMetaData</code> and <code>GetMetaData</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx<span class="token punctuation">.</span><span class="token function">SetMetaData</span><span class="token punctuation">(</span><span class="token string">&quot;source&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;cron_A&quot;</span><span class="token punctuation">)</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">SetMetaData</span><span class="token punctuation">(</span><span class="token string">&quot;user_id&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;42&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">meta <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetMetaData</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// Meta{&quot;source&quot;: &quot;cron_A&quot;, &quot;user_id&quot;: &quot;42&quot;}</span></span>
<span class="line">value <span class="token operator">:=</span> meta<span class="token punctuation">.</span><span class="token function">Get</span><span class="token punctuation">(</span><span class="token string">&quot;source&quot;</span><span class="token punctuation">)</span> <span class="token comment">// &quot;cron_A&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Metadata is useful for tagging queries with request information (e.g., which API endpoint or background job triggered them), which can then be used in query loggers or metrics.</p><h2 id="cloning-a-context" tabindex="-1"><a class="header-anchor" href="#cloning-a-context"><span>Cloning a Context</span></a></h2><p>You can create as many <code>Context</code> instances as needed. However, if you want to share settings like metadata and debug mode across multiple contexts, use <code>Clone()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">SetMetaData</span><span class="token punctuation">(</span><span class="token string">&quot;admin_user_id&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;34&quot;</span><span class="token punctuation">)</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">EnableQueryDebug</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Clone shares metadata and debug settings</span></span>
<span class="line">ctx2 <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">ctx2<span class="token punctuation">.</span><span class="token function">GetMetaData</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// Meta{&quot;admin_user_id&quot;: &quot;34&quot;}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Clone()</code> creates a new <code>Context</code> that inherits:</p><ul><li>Metadata</li><li>Debug/logger settings</li><li>Context cache settings (disabled state, TTL)</li></ul><p>The cloned context has its own tracking state -- entities tracked in the original context are not tracked in the clone. Each context flushes independently.</p><h3 id="clone-with-a-different-context-context" tabindex="-1"><a class="header-anchor" href="#clone-with-a-different-context-context"><span>Clone with a Different context.Context</span></a></h3><p>Use <code>CloneWithContext()</code> to create a clone with a different <code>context.Context</code>, useful for sub-requests with different deadlines:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">ctx<span class="token punctuation">.</span><span class="token function">SetMetaData</span><span class="token punctuation">(</span><span class="token string">&quot;request_id&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;abc123&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">subCtx <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">CloneWithContext</span><span class="token punctuation">(</span></span>
<span class="line">    context<span class="token punctuation">.</span><span class="token function">WithTimeout</span><span class="token punctuation">(</span>r<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="context-cache" tabindex="-1"><a class="header-anchor" href="#context-cache"><span>Context Cache</span></a></h2><p>The Context includes a short-lived, per-request entity cache. When an entity is loaded (e.g., via <code>GetByID</code>), it is stored in the context cache. Subsequent requests for the same entity within the same Context return the cached instance without hitting Redis or MySQL.</p><h3 id="disabling-context-cache" tabindex="-1"><a class="header-anchor" href="#disabling-context-cache"><span>Disabling Context Cache</span></a></h3><p>If you need to always fetch fresh data:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx<span class="token punctuation">.</span><span class="token function">DisableContextCache</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="setting-context-cache-ttl" tabindex="-1"><a class="header-anchor" href="#setting-context-cache-ttl"><span>Setting Context Cache TTL</span></a></h3><p>The default TTL is 1 second. You can adjust it:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx<span class="token punctuation">.</span><span class="token function">SetContextCacheTTL</span><span class="token punctuation">(</span><span class="token number">5</span> <span class="token operator">*</span> time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>After the TTL expires, the cache is cleared on the next access, and entities are loaded fresh from the data source.</p><h2 id="database-pipeline" tabindex="-1"><a class="header-anchor" href="#database-pipeline"><span>Database Pipeline</span></a></h2><p>For batch SQL operations within a single connection, use <code>DatabasePipeLine()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">pipeline <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">DatabasePipeLine</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line">pipeline<span class="token punctuation">.</span><span class="token function">AddQuery</span><span class="token punctuation">(</span><span class="token string">&quot;INSERT INTO logs (message) VALUES (?)&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;event happened&quot;</span><span class="token punctuation">)</span></span>
<span class="line">pipeline<span class="token punctuation">.</span><span class="token function">AddQuery</span><span class="token punctuation">(</span><span class="token string">&quot;UPDATE counters SET count = count + 1 WHERE name = ?&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;events&quot;</span><span class="token punctuation">)</span></span>
<span class="line">err <span class="token operator">:=</span> pipeline<span class="token punctuation">.</span><span class="token function">Exec</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The database pipeline batches multiple SQL statements and executes them efficiently. Internally, <code>Flush()</code> uses database pipelines to batch all entity INSERT/UPDATE/DELETE operations.</p><h2 id="redis-pipeline" tabindex="-1"><a class="header-anchor" href="#redis-pipeline"><span>Redis Pipeline</span></a></h2><p>For batch Redis operations, use <code>RedisPipeLine()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">pipeline <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">RedisPipeLine</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line">pipeline<span class="token punctuation">.</span><span class="token function">Set</span><span class="token punctuation">(</span><span class="token string">&quot;key1&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;value1&quot;</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span></span>
<span class="line">pipeline<span class="token punctuation">.</span><span class="token function">Set</span><span class="token punctuation">(</span><span class="token string">&quot;key2&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;value2&quot;</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span></span>
<span class="line">result<span class="token punctuation">,</span> err <span class="token operator">:=</span> pipeline<span class="token punctuation">.</span><span class="token function">Exec</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Redis pipelines are also used internally by <code>Flush()</code> to batch all Redis cache updates.</p><h2 id="event-broker" tabindex="-1"><a class="header-anchor" href="#event-broker"><span>Event Broker</span></a></h2><p>The Context provides access to an event broker for entity lifecycle events:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">broker <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetEventBroker</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>The event broker allows you to subscribe to entity changes (inserts, updates, deletes) and publish custom events. See the Event Broker documentation for details.</p><h2 id="accessing-the-engine" tabindex="-1"><a class="header-anchor" href="#accessing-the-engine"><span>Accessing the Engine</span></a></h2><p>You can always access the <code>Engine</code> from a <code>Context</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">engine <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Engine</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">db <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Engine</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">DB</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line">redis <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Engine</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Redis</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="accessing-the-underlying-context-context" tabindex="-1"><a class="header-anchor" href="#accessing-the-underlying-context-context"><span>Accessing the Underlying context.Context</span></a></h2><p>To retrieve the standard <code>context.Context</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">stdCtx <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>This is useful when you need to pass the context to non-FluxaORM functions that expect a <code>context.Context</code>.</p>`,77)]))}const l=s(o,[["render",c]]),u=JSON.parse('{"path":"/guide/context.html","title":"Context","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772457520000,"contributors":[{"name":"Lukasz Lato","username":"","email":"lukasz.lato@summer-solutions.com","commits":15},{"name":"lukaszjezapkowicz","username":"lukaszjezapkowicz","email":"ljezapkowicz@gamesture.com","commits":1,"url":"https://github.com/lukaszjezapkowicz"},{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":9,"url":"https://github.com/lukaszlato"},{"name":"Claude Opus 4.6","username":"","email":"noreply@anthropic.com","commits":2}],"changelog":[{"hash":"c7abb617d848487b26523673384942aaa8151e75","time":1772457520000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"Lifecycle callbacks"},{"hash":"0d95083128230edc85715b91f869a59fd4685135","time":1772364739000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"Remove NewWithFields() documentation","coAuthors":[{"name":"Claude Opus 4.6","email":"noreply@anthropic.com"}]},{"hash":"404a5f0ff667daa899361c14fb2125ea9179752e","time":1772296544000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"Document NewWithFields() method for entity creation","coAuthors":[{"name":"Claude Opus 4.6","email":"noreply@anthropic.com"}]},{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"316a31e0c87cadff2385ecc502474311a5584360","time":1703064516000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"cec00bb528a21f7b1fd09751bcc9c9c023d4d37d","time":1699022416000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"40eeb7f270c5a1d4e8d4f0f5b4e962ed8d439479","time":1698733999000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"0059a19c2126e4b7c2073e6714d9e2b7c1e509d5","time":1698392600000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"3801ae9ffe94ea2f358b357e32800a6cd2a53c29","time":1698326864000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"ff683e55c7a242c1babb40f3a30cb2e88a50db1c","time":1677766535000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"new documentation"},{"hash":"2af5dc7dffaf41a0256d9fe25d493a66879d754e","time":1675260339000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"new documentation"},{"hash":"b905fe3e2a0658d158ce9dff4d1bb299866a698e","time":1671799025000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"entity.Clone()"},{"hash":"95d6ef3193fc4dd4cd099c28beb0851d57d1041d","time":1671719480000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"entity.Clone()"},{"hash":"5afb0e806e399f08100a9f3b82a7eef86194880e","time":1659608166000,"email":"ljezapkowicz@gamesture.com","author":"lukaszjezapkowicz","message":"typos part 1"},{"hash":"ab2ad53b6a534be4cba3768ed94da50630c75a0b","time":1629702328000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"1a84fe401aac546f204f5a30104fd0813d783458","time":1628088902000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"3dcdd30df7e626335e7266dbee99a6fa316a7ef0","time":1627736910000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"6381bbb4e209f50e103b5491f335471d34e26097","time":1626455326000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"75ca86878ab9f1b034ce1c825899a3cdca85a465","time":1626348088000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"92d8d0dea3c6cab5047a5de1ea37018d0617d2d5","time":1624023563000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"40d2ce122af6451eb0df3024dc3974196a672f27","time":1623318992000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"089521e559bd0959f0df8cf9ac91dbf8be536790","time":1619602115000,"email":"lukasz.lato@summer-solutions.com","author":"Lukasz Lato","message":"favicon"},{"hash":"a6b58944f27ffe8e477ed599eee5c0b99961f9b4","time":1619601160000,"email":"lukasz.lato@summer-solutions.com","author":"Lukasz Lato","message":"favicon"},{"hash":"642ca751fcd5fe825262f0a145c9e83f07070c20","time":1619600784000,"email":"lukasz.lato@summer-solutions.com","author":"Lukasz Lato","message":"favicon"},{"hash":"d190e784e0fc1d2ce789195c9d540c75a634d0ad","time":1619524901000,"email":"lukasz.lato@summer-solutions.com","author":"Lukasz Lato","message":"favicon"}]},"filePathRelative":"guide/context.md"}');export{l as comp,u as data};
